    async def modify_order(
        self,
        *,
        market: str,
        request: str,
        nonce: str,
        order_id: typing.Optional[int] = OMIT,
        client_order_id: typing.Optional[str] = OMIT,
        amount: typing.Optional[str] = OMIT,
        total: typing.Optional[str] = OMIT,
        price: typing.Optional[str] = OMIT,
        activation_price: typing.Optional[str] = OMIT,
        request_options: typing.Optional[RequestOptions] = None,
    ) -> OrderResponse:
        """
        The endpoint modifies existing [order](/glossary#orders).

        Supported order types: limit, stop limit, stop market.

        Request must contain one of the following parameters: amount, price, activationPrice.

        <Warning>
        Rate limit: 10000 requests/10 sec.
        </Warning>

        <Note>
        - Use total parameter instead of amount for modify buy stop market order.
        - Modification by client_order_id takes priority.
        - The request supports working only with order_id or only with client_order_id.
        - Do not pass both values at the same time.
        </Note>

        <Accordion title="Error Codes">
        **Status 400** (client errors): 1, 2, 6, 20, 24, 101, 158

        **Status 422** (business logic): 10, 11, 12, 13, 14, 15, 16, 17, 25, 27, 40, 42, 51, 103, 104, 105, 106, 111, 112, 113, 114, 115, 150, 151, 152, 153, 155, 157, 159, 160, 161, 162, 163, 250, 251, 300, 302, 330
        </Accordion>

        <Accordion title="Errors">
        ```json
        {
          "code": 31,
          "message": "Validation failed",
          "errors": {
            "market": ["Market is not available."]
          }
        }
        ```

        ```json
        {
          "code": 2,
          "message": "Inner validation failed",
          "errors": {
            "order_id": ["Unexecuted order was not found."]
          }
        }
        ```

        ```json
        {
          "code": 10,
          "message": "Validation failed",
          "errors": {
            "amount": ["Not enough balance."]
          }
        }
        ```
        </Accordion>

        Parameters
        ----------
        market : str
            Available [market](/glossary#market). Example: BTC_USDT

        request : str

        nonce : str

        order_id : typing.Optional[int]
            Active order id. Required if client_order_id is not set.

        client_order_id : typing.Optional[str]
            Identifier should be unique and contain letters, dashes, numbers, dots or underscores. Required if order_id is not set.

        amount : typing.Optional[str]
            Amount of [stock](/glossary#stock) currency to buy or sell. Example: '0.001' or 0.001

        total : typing.Optional[str]
            Total of [money](/glossary#money) currency to buy or sell. Example: '0.001' or 0.001

        price : typing.Optional[str]
            Price in [money](/glossary#money) currency. Example: '9800' or 9800

        activation_price : typing.Optional[str]
            Activation price in [money](/glossary#money) currency. Example: '10000' or 10000

        request_options : typing.Optional[RequestOptions]
            Request-specific configuration.

        Returns
        -------
        OrderResponse
            Order modified successfully

        Examples
        --------
        from whitebit import AsyncWhitebitApi
        import asyncio
        client = AsyncWhitebitApi(txc_apikey="YOUR_TXC_APIKEY", token="YOUR_TOKEN", )
        async def main() -> None:
            await client.spot_trading.modify_order(market='BTC_USDT', request='{{request}}', nonce='{{nonce}}', )
        asyncio.run(main())
        """
        _response = await self._raw_client.modify_order(
            market=market,
            request=request,
            nonce=nonce,
            order_id=order_id,
            client_order_id=client_order_id,
            amount=amount,
            total=total,
            price=price,
            activation_price=activation_price,
            request_options=request_options,
        )
        return _response.data

    async def set_kill_switch(
        self,
        *,
        market: str,
        timeout: str,
        types: typing.Optional[typing.Sequence[SetKillSwitchRequestTypesItem]] = OMIT,
        request: typing.Optional[str] = OMIT,
        nonce: typing.Optional[str] = OMIT,
        request_options: typing.Optional[RequestOptions] = None,
    ) -> SetKillSwitchResponse:
        """
        The endpoint creates, updates, deletes [kill-switch timer](/glossary#kill-switch-timer).

        <Warning>
        Rate limit: 10000 requests/10 sec.
        </Warning>

        <Note>
        - If timeout=null - delete existing timer by market.
        - If types=null - create timer by market for all order types.
        </Note>

        <Accordion title="Error Codes">
        - `30` - default validation error code
        - `31` - market validation failed
        </Accordion>

        <Accordion title="Errors">
        ```json
        {
          "code": 30,
          "message": "Validation failed",
          "errors": {
            "market": ["Market field is required."],
            "timeout": ["Timeout field is required."]
          }
        }
        ```

        ```json
        {
          "code": 31,
          "message": "Validation failed",
          "errors": {
            "market": ["Market is not available."]
          }
        }
        ```

        ```json
        {
          "code": 30,
          "message": "Validation failed",
          "errors": {
            "timeout": ["Timeout should be at least 5."]
          }
        }
        ```
        </Accordion>

        Parameters
        ----------
        market : str
            Available [market](/glossary#market). Example: BTC_USDT

        timeout : str
            Timer value. Example: '5'-'600' or null

        types : typing.Optional[typing.Sequence[SetKillSwitchRequestTypesItem]]
            Order types value. Example: 'spot', 'margin', 'futures' or null

        request : typing.Optional[str]

        nonce : typing.Optional[str]

        request_options : typing.Optional[RequestOptions]
            Request-specific configuration.

        Returns
        -------
        SetKillSwitchResponse
            Successful response - kill-switch timer synced

        Examples
        --------
        from whitebit import AsyncWhitebitApi
        import asyncio
        client = AsyncWhitebitApi(txc_apikey="YOUR_TXC_APIKEY", token="YOUR_TOKEN", )
        async def main() -> None:
            await client.spot_trading.set_kill_switch(market='BTC_USDT', timeout='60', )
        asyncio.run(main())
        """
        _response = await self._raw_client.set_kill_switch(
            market=market, timeout=timeout, types=types, request=request, nonce=nonce, request_options=request_options
        )
        return _response.data

